sqlServer.code:
-- Check current memory settings (readable without sysadmin)
SELECT
    name,
    value_in_use AS current_value_mb,
    minimum,
    maximum,
    description
FROM sys.configurations
WHERE name IN ('max server memory (MB)', 'min server memory (MB)');

-- Set max server memory to 8 GB (requires sysadmin role)
EXEC sp_configure 'show advanced options', 1;
RECONFIGURE;
EXEC sp_configure 'max server memory (MB)', 8192;
RECONFIGURE;

-- Verify the change
SELECT name, value_in_use AS current_value_mb
FROM sys.configurations
WHERE name = 'max server memory (MB)';

-- View current parallelism settings
SELECT
    name,
    value_in_use AS current_value,
    minimum,
    maximum,
    description
FROM sys.configurations
WHERE name IN (
    'max degree of parallelism',
    'cost threshold for parallelism'
);

-- Set MAXDOP to 4 and cost threshold to 25 (requires sysadmin)
EXEC sp_configure 'show advanced options', 1;
RECONFIGURE;
EXEC sp_configure 'max degree of parallelism', 4;
EXEC sp_configure 'cost threshold for parallelism', 25;
RECONFIGURE;

-- Override MAXDOP at query level (no special permissions needed)
SELECT TOP 100 *
FROM sys.objects
ORDER BY name
OPTION (MAXDOP 1);

postgres.code:
-- View current parallelism settings
SELECT name, setting, unit, context, short_desc
FROM pg_settings
WHERE name IN (
    'max_parallel_workers_per_gather',
    'max_parallel_workers',
    'parallel_setup_cost',
    'parallel_tuple_cost',
    'min_parallel_table_scan_size',
    'min_parallel_index_scan_size'
)
ORDER BY name;

-- Change server-wide parallelism settings (requires superuser)
ALTER SYSTEM SET max_parallel_workers_per_gather = 4;
ALTER SYSTEM SET max_parallel_workers = 8;
ALTER SYSTEM SET parallel_setup_cost = 500;
SELECT pg_reload_conf();

-- Override parallelism for a single session (like MAXDOP query hint)
SET max_parallel_workers_per_gather = 1;  -- disable parallelism for this session

-- Verify current session setting
SHOW max_parallel_workers_per_gather;

-- Reset to server default
RESET max_parallel_workers_per_gather;
